    // Inicializar todos los carruseles
    document.querySelectorAll('.carousel').forEach(function(carousel) {
        var inner = carousel.querySelector('.carousel-inner');
        var items = carousel.querySelectorAll('.carousel-item');
        var images = carousel.querySelectorAll('.carousel-item img');
        var prev = carousel.querySelector('.carousel-prev');
        var next = carousel.querySelector('.carousel-next');
        var currentIndex = 0;

        function moveTo(index) {
            if (index = items.length) index = 0;
            inner.style.transform = 'translateX(-' + (index * 100) + '%)';
            currentIndex = index;
        }

        prev.addEventListener('click', function(e) {
            e.stopPropagation();
            moveTo(currentIndex - 1);
        });

        next.addEventListener('click', function(e) {
            e.stopPropagation();
            moveTo(currentIndex + 1);
        });

        var touchStartX = 0;
        var touchEndX = 0;

        carousel.addEventListener('touchstart', function(e) {
            touchStartX = e.touches[0].clientX;
        }, false);

        carousel.addEventListener('touchend', function(e) {
            touchEndX = e.changedTouches[0].clientX;
            handleSwipe();
        }, false);

        function handleSwipe() {
            var difference = touchStartX - touchEndX;
            if (Math.abs(difference) > 50) {
                if (difference > 0) {
                    moveTo(currentIndex + 1);
                } else {
                    moveTo(currentIndex - 1);
                }
            }
        }

        images.forEach(function(img, index) {
            img.addEventListener('click', function() {
                openModal(this.src, index, images);
            });
        });
    });

    var modal = document.getElementById('imageModal');
    var modalImg = document.getElementById('modalImage');
    var closeBtn = document.querySelector('.modal-close');
    var modalPrev = modal.querySelector('.modal-prev');
    var modalNext = modal.querySelector('.modal-next');
    var currentImages = [];
    var currentImageIndex = 0;

    function openModal(src, index, images) {
        modal.style.display = 'flex';
        modalImg.src = src;
        currentImages = Array.from(images);
        currentImageIndex = index;
    }

    function moveModal(direction) {
        currentImageIndex += direction;
        if (currentImageIndex >= currentImages.length) currentImageIndex = 0;
        if (currentImageIndex  50) {
            if (difference > 0) {
                moveModal(1);
            } else {
                moveModal(-1);
            }
        }
    }
